var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 오랫동안 숲을 헤매며 요정을 찾아 다녔습니다.","JPN":"少女は長いあいだ森の中をさまよいながら妖精をさがしました。","ENG":"The girl wandered from forest to forest, looking for the fairy.","TWN":"少女為了尋找妖精，在森林中徘徊了很久。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그러던 중 동물들을 마주쳤죠.","JPN":"そんな中、動物たちに出会いました。","ENG":"Along the way, she met some animals.","TWN":"她在路上遇到了一些動物。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사자도, 곰도 기운이 없어 보였어요.","JPN":"しかしライオンもクマも、どこか元気がありませんでした。","ENG":"But neither the lion nor the bear looked happy.","TWN":"但是獅子和熊都是一副有氣無力的樣子。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그 동물들은 사실 철창으로 된 우리에 갇힌 채 자유롭지 못했답니다.","JPN":"その動物たちは鉄檻に閉じ込められ、身動きが\\nとれない状態だったのです。","ENG":"They weren't free to move, locked up behind iron bars.","TWN":"原來那些動物都被關在鐵籠子裡。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"동물들은 밀렵꾼에게 잡혔고, 곧 서커스에 팔려갈 처지였죠.","JPN":"動物たちは密猟者に捕まり、間もなくサーカス団に\\n売られる運命でした。","ENG":"The poacher who caught them was going to sell them to a circus troupe.","TWN":"這些動物是被偷獵者獵捕的，馬上就會被賣給馬戲團。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"이를 안타깝게 여긴 소녀는 동물들을 풀어주기로 했습니다.","JPN":"これをかわいそうに思った少女は、動物たちを\\n解放してあげようと思いました。","ENG":"Feeling sorry for them, the girl decided to let them go.","TWN":"善良的少女決定放走那些動物。"},"stage":{"bg":"EV_SIGMA_06","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"어이 신참! 해체 준비는 끝났나?!","JPN":"おい、新入り！　解体の準備は済んだのか！？","ENG":"Hey, rookie! Is it ready for disassembly?","TWN":"喂，新人！準備好拆解了嗎？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"네, 작업대에 고정은 마쳤습니다. 이제 대장님만 오시면 됩니다!","JPN":"はい、作業台に固定しました。後は隊長の帰りを\\n待つだけです！","ENG":"Yes, it's been strapped to the workbench. Now all we need to do is just wait for the Captain.","TWN":"是，已經固定到工作臺上了，等隊長回來就能開始！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"그런데 정말 이런 거대한 로봇을 저희 편으로 만들 수 있는 겁니까?","JPN":"でも、本当にこんな巨大なロボットを味方に\\nつけられるんですかね？","ENG":"By the way, are you sure we can turn such a big robot to our side?","TWN":"但是真的能把這巨大的機器人改造成我方戰力嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"당연하지. 우리 대장님 이름은 단순히 기계를 좋아해서 붙은 별명이 아니거든.","JPN":"当然だ。うちの隊長のあだ名はな、単に機械好きだから\\nつけられたものではないぞ。","ENG":"Of course. The Captain isn't simply called the Machine Collector because she likes machines.","TWN":"當然，我們隊長可不是浪得虛名。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"대장님의 능력은 이런 인공지능 로봇들을 꼭두각시로 만드는데 특화돼있어.","JPN":"隊長の能力はこのような人工知能ロボットを操るのに\\n特化しているんだ。","ENG":"She specializes in turning AI robots like this into her puppets.","TWN":"隊長可以用自己的能力將這些人工智慧機器人改造成他的傀儡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"대장님이 카운터란 얘긴 이곳에 오기 전부터 들었지만...... 정말 그런 것도 가능한 겁니까?","JPN":"隊長がカウンターだということは聞いていましたが……\\n本当にそんなことまで可能なんですか？","ENG":"I heard she's a Counter before I even joined this group, but is that really possible?","TWN":"雖然早就聽說隊長是制裁者……但真的連那種事情都做到嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"듣기론 기계를 조종하는 조그만 기생충을 부린다던데, 직접 말해주신 게 없으니 정확한 건 나도 몰라.","JPN":"噂では機械を操れる小さな寄生虫を持っているとか。\\nけど、本人から聞いたわけじゃないから実際の\\nところはわからない。","ENG":"Rumor has it that she uses tiny parasites to control machines, but I don't know if that's true. I didn't ask her.","TWN":"我聽說他能使喚操控機械的寄生蟲，我也不知道具體是怎麼做到的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"......함선의 창고들이 전부 메카닉으로 가득하던데, 대장님은 기계를 정말 좋아하시나 보네요.","JPN":"……艦船の倉庫はメカニックだらけでしたけど、隊長は\\n本当に機械好きなんですね。","ENG":"The hold in this ship is filled with mechs. The Captain really must love machines.","TWN":"……艦船的倉庫塞滿了裝甲部隊，看來隊長真的很喜歡機械。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"글쎄. 대장님이 <color=#ffd34c>작품</color>을 개조하는 과정을 직접 보고 나면 좋아한다는 말은 어울리지 않는단 걸 너도 알게 될 거다.","JPN":"どうかな。隊長が<color=#ffd34c>コレクション</color>を改造する過程を目の当たりに\\nしたら、「好き」という言葉は適していないことがわかるだろうよ。","ENG":"I don't know. If you see her working on her <color=#ffd34c>pieces</color>, you might not say she loves them.","TWN":"未必，如果你親眼看到隊長改造<color=#ffd34c>作品</color>的過程，你就不會這麼說了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"네? 그게 무슨......","JPN":"はい？　それはどういう……","ENG":"Sorry? I don't understand...","TWN":"什麼？什麼意思……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"우왓! 뭐야, 이 충격은?","JPN":"うわっ！　なんだ、この衝撃は？","ENG":"Wah! W-what happened?","TWN":"嗚哇！怎麼回事？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이봐, 너희들!","JPN":"おい、そこのお前ら！","ENG":"Hey! You two!","TWN":"喂，你們！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L23_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"오셨습니까, 대장님!","JPN":"お帰りですか、隊長！","ENG":"Yes, ma'am!","TWN":"隊長，您來了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"적들이 함내로 쳐들어오기 직전이다!","JPN":"間もなく敵が艦内に押し寄せてくる！","ENG":"The enemies are about to break in!","TWN":"敵人馬上要攻入船艦內部了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"작업은 내가 혼자 진행할 테니 어서 나가서 아군을 지원하도록!","JPN":"作業は俺ひとりでやるから、ただちに仲間を支援しに行くように！","ENG":"I'll take care of this machine myself. Go out there and help the others.","TWN":"這裡我一個人就行，你們快去支援我方！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"옙! 알겠습니다!","JPN":"はい！　了解しました！","ENG":"Yes, ma'am!","TWN":"是！明白！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"엇, 하지만 분명 대장님은 좀 전에 놈들을 처리하고 오신다고......","JPN":"あれ？　でも、さっき隊長が奴らを片づけてくるって……","ENG":"But Captain, you just went out there to take care of them—","TWN":"呃，但是剛才隊長明明說過要去對付敵人……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"어이, 대장님 명령이다.","JPN":"おい、隊長命令だぞ。","ENG":"Hey rookie, the Captain has spoken.","TWN":"喂，這是隊長的命令。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"신참 주제에 눈치 없게 대장님 말씀에 트집 잡지 말고 따라와!","JPN":"新入りのくせに隊長に口答えするんじゃねえ。\\nついてこい！","ENG":"Just shut up and follow me.","TWN":"你一個新人還敢找隊長的茬，快跟我來！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はい！","ENG":"Y-yes, sir!","TWN":"是，是！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"흐음...... 난감하군.","JPN":"ふむ……こいつは困ったな。","ENG":"Hmm... This is not good.","TWN":"嗯……不妙啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"밖에서 전투가 벌어진 것 같은데......","JPN":"外で戦闘が始まったようだが……","ENG":"I can hear the fight taking place outside.","TWN":"外面好像發生了戰鬥……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그 호송대장 친구, 정말로 날 위해 구조대를 보낸 건가?","JPN":"あの搬送隊長、本当に吾輩のために救助隊を\\n派遣させたんだろうか？","ENG":"Did the convoy captain really send me help?","TWN":"那個護送隊長，真的為了救我派來了救助隊？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"고맙긴 하지만, 그러다가 누가 다치기라도 하면 큰일인데......","JPN":"ありがたいが、誰か途中でケガでもしたら大変だ……","ENG":"I'm grateful, but I don't want anyone to get hurt on my behalf...","TWN":"雖然很感謝，但萬一有人受傷就不好了……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그럼 같이 도와주러 가자.","JPN":"だったら、一緒に助けに行こうよ。","ENG":"Then, let's go help those out there.","TWN":"那就一起去幫忙吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"위기에 빠진 사람들을 돕는 세기말 결전병기랬잖아?","JPN":"危機に瀕した人々を助けるための世紀末決戦兵器って\\n言ってたよね？","ENG":"You said us Ultimate Doomsday Weapons are to help people in distress.","TWN":"你不是拯救陷入危險之人的決戰兵器嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음? 무슨 말인가?","JPN":"ん？　何を言ってるんだ？","ENG":"Mm? Pardon?","TWN":"嗯？你在說什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미안하지만 난 자네 같은 불법적인 해적들의 일을 도와줄 수는 없네.","JPN":"悪いが吾輩は貴様らのような海賊の違法行為に\\n手を貸すわけにはいかないのだ。","ENG":"I'm sorry, but I don't intend to help you pirates.","TWN":"很抱歉，我不會和你這樣的海盜一起做犯法的事情。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그리고, 자네가 내게 어떤 짓을 하더라도 날 굴복시키는 건 쉽지 않을 거라고 미리 말해두지!","JPN":"それからあらかじめ言っておくが、貴様が吾輩に何をしようとも、簡単には屈服させられないぞ。","ENG":"Also, I'll have you know that whatever you do, I'll fight against it for as long as I can.","TWN":"還有，你不管對我做什麼，我也不會屈服的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"푸훗......","JPN":"ぷっ……","ENG":"Poof!","TWN":"噗……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"아하하하!","JPN":"あははは！","ENG":"Ah hah hah hah!","TWN":"啊哈哈哈！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"할아버지도 이 모습에 깜박 속은 거야?","JPN":"おじいちゃんもこの姿に騙されたのね？","ENG":"Grandpa, can't you tell who I am?","TWN":"爺爺也被我騙到了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"짜잔! 사실은 나야!","JPN":"じゃじゃーん！　私だよ！","ENG":"Tah-dah! It's me!","TWN":"噔噔！其實是我啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_03"},{"id":"L46_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어때? 굉장하지?","JPN":"どう？　すごいでしょう？","ENG":"Say, awesome, isn't it?","TWN":"怎麼樣？很厲害吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"아니, 자네는 격납고에서 본 꼬마 아가씨 아닌가!","JPN":"き、君は格納庫で会ったお嬢ちゃんじゃないか！","ENG":"Ah? You're the little lady I met at the hangar!","TWN":"咦，你不是上次在機庫遇到的小妹妹嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예? 특별한 용도요?","JPN":"え？　特別な用途ですか？","ENG":"Pardon? A special purpose?","TWN":"嗯？特殊用途？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 관리국의 기술을 노리던 자들은 언제나 있어왔으니까.","JPN":"そうだ。管理局の技術を狙う奴らはいつだっているからな。","ENG":"Yes. There always have been people who have an eye on the Administration's technology.","TWN":"沒錯，一直以來總有人對管理局的技術虎視眈眈。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마 넘버링은 그런 공격에 대응하기 위해 만들어진 수단.","JPN":"シグマ・ナンバリングはそんな攻撃に対応するために設けられた手段。","ENG":"The Sigma series was created in response to their attacks.","TWN":"而西格瑪系列正是為了應對他們的攻擊而製作出來的。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적어도 기계장치에 한해서는 어떠한 전자적 공격도 막아낼 수 있는 백신이지.","JPN":"少なくとも機械装置に限っては、あらゆる電子攻撃を\\n防ぐことができるワクチンだ。","ENG":"It's an antivirus that can block all electronic attacks on machinery.","TWN":"至少對於機械設備而言，它可以說是能阻擋任何一種電子攻擊的疫苗。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 기억은 잃었지만, 자신이 가진 능력이 어떤 것인지 본능적으로 깨달을 걸세.","JPN":"記憶を失ってはいるが、自分の持つ能力がいかにすごいか\\n本能的に気が付くだろう。","ENG":"She may have lost her memories, but she instinctively knows what her prime duty is.","TWN":"雖然它丟失了記憶，但應該會本能地領悟到自己擁有的能力。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이걸 풀어줄게. 잠깐만 기다려.","JPN":"これを解いてあげるから。ちょっと待っててね。","ENG":"Let me release you. Give me a moment.","TWN":"等等，我幫你解開。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"잠깐! 그만두게!","JPN":"だめだ！　やめておけ！","ENG":"Wait, don't.","TWN":"不！停下！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"고정장치를 해제한다고 해도 나와 여기에 있는 친구들은 이 해적들의 우두머리에게 조종당하고 있다네.","JPN":"固定装置を解除しても、吾輩やここにいる仲間は\\n海賊団の親玉に操られている。","ENG":"Even if you release us, all of us here are being controlled by the pirate leader.","TWN":"解除固定裝置也沒用，我和這裡的其他朋友都已經被海盜頭目操控了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그래서는 아군의 짐이 될 뿐이야!","JPN":"このままでは味方のお荷物になるだけだ！","ENG":"We'll only be a burden to our allies.","TWN":"我們會拖累我方的！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 조종당하지 않도록 내가 지켜주면 괜찮지?","JPN":"だったら、操られないように私が守ってあげればいいよね？","ENG":"Then, how about I protect you against her control?","TWN":"那我來保護你們不被操控就可以了吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......자네가? 하지만 어떻게?","JPN":"君が……？　どうやって？","ENG":"You? But how?","TWN":"……你？你要怎麼做？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그야 나한텐 별로 어려운 일도 아닌걸?","JPN":"そんなの、私にとって別に難しいことでもないよ？","ENG":"Well, it's something I can do easily.","TWN":"這對我來說很簡單呀？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 그렇게까지 말한다면 부디 부탁하겠네!","JPN":"うむ！　そこまで言うなら頼むぞ！","ENG":"Mm... Okay, then please help us.","TWN":"嗯！既然這樣，那就拜託你了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"시그마 프로토콜 개방...... 프로텍션 커넥트. 올 그린!","JPN":"シグマ・プロトコルを開放……プロテクション・コネクト。\\nオールグリーン！","ENG":"Unlocking Sigma Protocol... Enabling protection... All lights are green.","TWN":"西格瑪協定開放……防護連接．全綠！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"자, 언니오빠들~","JPN":"さあ、お姉ちゃんたち、お兄ちゃんたち！","ENG":"Now, brothers and sisters.","TWN":"來，哥哥姐姐們～"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이제 일어날 시간이야.","JPN":"そろそろ起きる時間だよ。","ENG":"It's time to wake up.","TWN":"該起床啦。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"......시스템 리부팅 완료","JPN":"……システム・リブート完了。","ENG":"System reboot completed.","TWN":"......系統重啟完畢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L21_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"아라크네. 새로운 명령권자를 확인했습니다.","JPN":"アラクネ、新しい命令権者を確認しました。","ENG":"Arachne has acknowledged the new commander.","TWN":"阿拉克涅，確認新的命令權者。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"아라크네! 정신이 드는가?","JPN":"アラクネ！　気がついたか？","ENG":"Arachne! Are you okay now?","TWN":"阿拉克涅！你醒了嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"본 기체의 인공지능 시스템에는 이상이 없습니다.","JPN":"本機の人工知能システムに異常はありません。","ENG":"My AI system is fully functioning.","TWN":"本機體的人工智慧未發現異常。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"확인 감사합니다.","JPN":"ご確認ありがとうございます。","ENG":"Thank you for checking on me.","TWN":"感謝確認。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 나도 몸을 마음대로 움직일 수 있게 됐군!","JPN":"うむ！　吾輩も自由に体を動かせるようになったな！","ENG":"Mm, I too can move my body again.","TWN":"嗯！我身體的控制權又回來了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"오히려 더 홀가분해진 느낌이야!","JPN":"むしろ以前よりも身が軽くなった気がするぞ！","ENG":"Better still, I feel much lighter on my feet!","TWN":"而且感覺渾身輕鬆！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이렇게 조그만 자네에게 그런 힘이 있었다니 정말 놀랍군!","JPN":"小さい体にそんな力が秘められているなんて、\\n本当に驚きだな。","ENG":"Who knew such a tiny thing like you could be so powerful?","TWN":"沒想到小小的你擁有如此驚人的力量！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Heh!","TWN":"嗯！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"잘은 몰라도 나, 고장 난 건 잘 고치니까! 어쩐지 할 수 있을 거라는 느낌이 들었어!","JPN":"よくわかんないけど、壊れたものの修理は得意だから！\\nなんとなくできそうな気がしたの！","ENG":"I don't know how, but I'm good at fixing things! So I thought I could do it!","TWN":"因為我很擅長修理故障！所以我覺得自己能做好！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어때? 나 대단하지? 칭찬해주고 싶지 않아?","JPN":"どう？　私すごいでしょう？　褒めたくなるでしょう？","ENG":"Say, I'm awesome, am I not? You want to say something nice to me, don't you?","TWN":"怎麼樣？我是不是很了不起？要不要誇我一下呢？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"정말 훌륭하네! 자네의 도움은 내 비휘발성 내장메모리에 영구히 기록해두겠네!","JPN":"まことに素晴らしい！　この恩は吾輩の非揮発性\\n内蔵メモリーに永久に記録しておこう！","ENG":"You are incredible! Your help today will be forever saved on my non-volatile internal memory device.","TWN":"太棒了！我會在非揮發性記憶體裡永久記錄你的表現！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"부디 자네의 이름을 말해주게!","JPN":"ぜひ君の名前を教えてほしい！","ENG":"Please tell me your name.","TWN":"請告訴我你的名字！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 시그마! 아빠 딸이야!","JPN":"私はシグマ！　パパの娘だよ！","ENG":"I'm Sigma. Daddy's girl!","TWN":"我叫西格瑪！是我爸爸的女兒！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이번에도 잘 부탁해!","JPN":"今後もよろしくね！","ENG":"I'll leave everything else to you now!","TWN":"這次也拜託你了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};